"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[78457],{14276:e=>{e.exports=JSON.parse('{"tag":{"label":"storage","permalink":"/dst-api-webdocs/docs/tags/storage","allTagsPath":"/dst-api-webdocs/docs/tags","count":24,"items":[{"id":"game-scripts/prefabs/alterguardianhatshard","title":"Alterguardianhatshard","description":"A portable light-emitting storage container that holds a single Mushroom Spore and adjusts its light colour and appearance based on the spore type.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/alterguardianhatshard"},{"id":"game-scripts/prefabs/battlesong_container","title":"Battlesong Container","description":"A portable container prefab that functions as storage with burnable behavior, custom open/close sounds, and inventory integration for Wigfrid\'s battlesong-themed items.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/battlesong_container"},{"id":"game-scripts/prefabs/beargerfur_sack","title":"Beargerfur Sack","description":"A portable storage container that preserves items and emits frost effects when open on the ground.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beargerfur_sack"},{"id":"game-scripts/prefabs/birdcage","title":"Birdcage","description":"Manages the behavior of a birdcage that houses birds, handles feeding, interaction, sleeping cycles, and loot generation based on bird state and food type.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/birdcage"},{"id":"game-scripts/components/container","title":"Container","description":"Manages item storage and interactions for entities, providing slot-based inventory logic, opening/closing behavior, and item transfer operations.","permalink":"/dst-api-webdocs/docs/game-scripts/components/container"},{"id":"game-scripts/components/counter","title":"Counter","description":"Manages named numeric counters with support for increment/decrement, per-counter save filtering, and save/load persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/components/counter"},{"id":"game-scripts/prefabs/dragonfly_chest","title":"Dragonfly Chest","description":"A deployable storage chest that can be upgraded to provide infinite stack size and special loot behavior upon destruction or upgrade.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/dragonfly_chest"},{"id":"game-scripts/prefabs/fish_box","title":"Fish Box","description":"A storage structure that preserves fish and breaks into wreckage upon hammering, releasing contents and triggering platform leaks.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fish_box"},{"id":"game-scripts/prefabs/gelblob_storage","title":"Gelblob Storage","description":"Stores edible food items indefinitely by stopping their decay and preventing pick-up, and releases them with decay resumed upon taking.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gelblob_storage"},{"id":"game-scripts/components/hideout","title":"Hideout","description":"Manages an internal inventory of creatures, allowing an entity to store and release creature entities as needed\u2014typically used for nest-like or lair-like behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/components/hideout"},{"id":"game-scripts/prefabs/icebox","title":"Icebox","description":"A storage container with refrigeration properties that accepts loot on hammering and drops its contents when destroyed.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/icebox"},{"id":"game-scripts/prefabs/icepack","title":"Icepack","description":"A wearable storage container that keeps items cold and provides inventory space, equipped on the body slot.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/icepack"},{"id":"game-scripts/components/itemstore","title":"Itemstore","description":"Manages a storage list of item records for an entity, supporting adding, retrieving, saving, and loading of items without persisting the actual item instances.","permalink":"/dst-api-webdocs/docs/game-scripts/components/itemstore"},{"id":"game-scripts/components/knownlocations","title":"Knownlocations","description":"Manages a collection of named coordinate positions associated with an entity for persistent tracking and recall.","permalink":"/dst-api-webdocs/docs/game-scripts/components/knownlocations"},{"id":"game-scripts/prefabs/magician_chest","title":"Magician Chest","description":"Serves as a shadow dimension storage container for the Magician character, enabling item storage with burnable and hauntable properties.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/magician_chest"},{"id":"game-scripts/components/powerload","title":"Powerload","description":"Stores and manages a numeric power load value and idle state for an entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/powerload"},{"id":"game-scripts/prefabs/quagmire_safe","title":"Quagmire Safe","description":"A locked storage container used in the Quagmire biome, requiring a key to open.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_safe"},{"id":"game-scripts/components/shelf","title":"Shelf","description":"Manages items stored on a shelf entity, including item placement, retrieval, and accessibility state.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shelf"},{"id":"game-scripts/prefabs/slingshotammo_container","title":"Slingshotammo Container","description":"A portable container prefab that stores slingshot ammunition and automatically opens/closes with associated animations and sounds.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/slingshotammo_container"},{"id":"game-scripts/prefabs/spicepack","title":"Spicepack","description":"A wearable backpack item that provides inventory storage, functions as a food preserver, and responds to fire ignition and extinguishing by locking/unlocking its contents.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spicepack"},{"id":"game-scripts/brains/storage_robotbrain","title":"Storage Robotbrain","description":"Manages the decision-making logic for storage robots to pick up, store, and return items based on inventory state and fuel levels.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/storage_robotbrain"},{"id":"game-scripts/prefabs/tacklecontainer","title":"Tacklecontainer","description":"Implements a portable, burnable storage container for the Hermit character with animated open/close states and integration into the container and inventory systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tacklecontainer"},{"id":"game-scripts/prefabs/wardrobe","title":"Wardrobe","description":"A placeable structure component that allows players to store and manage items via an inventory interface, while supporting interaction callbacks, hammering, burning, and save/load persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wardrobe"},{"id":"game-scripts/prefabs/wortox_souljar","title":"Wortox Souljar","description":"Manages the Wortox character\'s soul storage jar, handling soul containment, leakage, usage display via finiteuses, and interactions like opening, closing, and hammering.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wortox_souljar"}],"unlisted":false}}')}}]);